 1→import type { Conversation } from "@/data/mockConversations";
 2→import styles from "./ConversationList.module.scss";
 3→
 4→interface ConversationListProps {
 5→  conversations: Conversation[];
 6→  onSelect: (id: string) => void;
 7→}
 8→
 9→function timeAgo(date: Date): string {
10→  const seconds = Math.floor((Date.now() - date.getTime()) / 1000);
11→  if (seconds < 60) return "now";
12→  const minutes = Math.floor(seconds / 60);
13→  if (minutes < 60) return `${minutes}m`;
14→  const hours = Math.floor(minutes / 60);
15→  if (hours < 24) return `${hours}h`;
16→  return `${Math.floor(hours / 24)}d`;
17→}
18→
19→export function ConversationList({ conversations, onSelect }: ConversationListProps) {
20→  return (
21→    <div className={styles.list}>
22→      {conversations.map((conv) => {
23→        const lastMsg = conv.messages[conv.messages.length - 1];
24→        return (
25→          <button
26→            key={conv.id}
27→            className={styles.item}
28→            onClick={() => onSelect(conv.id)}
29→          >
30→            <div className={styles.avatar}>{conv.candidateInitial}</div>
31→            <div className={styles.content}>
32→              <div className={styles.header}>
33→                <span className={styles.name}>{conv.candidateName}</span>
34→                {lastMsg && (
35→                  <span className={styles.time}>{timeAgo(lastMsg.timestamp)}</span>
36→                )}
37→              </div>
38→              {lastMsg && (
39→                <p className={styles.preview}>{lastMsg.text}</p>
40→              )}
41→            </div>
42→            {conv.unread > 0 && (
43→              <span className={styles.unreadBadge}>{conv.unread}</span>
44→            )}
45→          </button>
46→        );
47→      })}
48→    </div>
49→  );
50→}
