 1→import {
 2→  createContext,
 3→  useCallback,
 4→  useContext,
 5→  useState,
 6→  type ReactNode,
 7→} from "react";
 8→
 9→interface SidebarContextValue {
10→  open: boolean;
11→  toggle: () => void;
12→  close: () => void;
13→}
14→
15→const SidebarContext = createContext<SidebarContextValue | null>(null);
16→
17→export function SidebarProvider({ children }: { children: ReactNode }) {
18→  const [open, setOpen] = useState(false);
19→
20→  const toggle = useCallback(() => setOpen((prev) => !prev), []);
21→  const close = useCallback(() => setOpen(false), []);
22→
23→  return (
24→    <SidebarContext.Provider value={{ open, toggle, close }}>
25→      {children}
26→    </SidebarContext.Provider>
27→  );
28→}
29→
30→export function useSidebar() {
31→  const ctx = useContext(SidebarContext);
32→  if (!ctx) throw new Error("useSidebar must be used within SidebarProvider");
33→  return ctx;
34→}
